.game-image {
    width: 100%;
    height: 200px;
    object-fit: cover;
    background: #e0e0e0;
}

.game-info {
    padding: 15px;
}

.game-info h3 {
    color: #333;
    margin-bottom: 8px;
    font-size: 1.3em;
}

.game-info p {
    color: #666;
    font-size: 0.9em;
    line-height: 1.4;
    margin-bottom: 10px;
}

.play-btn {
    width: 100%;
    background: #667eea;
    color: white;
    border: none;
    padding: 10px;
    border-radius: 5px;
    cursor: pointer;
    font-weight: bold;
    transition: background 0.3s;
}

.play-btn:hover {
    background: #5568d3;
}

/* Modal Styles */
.modal {
    display: none;
    position: fixed;
    z-index: 1;
    left: 0;
    top: 0;
    width: 100%;
    height: 100%;
    background-color: rgba(0, 0, 0, 0.7);
}

.modal.active {
    display: flex;
    justify-content: center;
    align-items: center;
}

.modal-content {
    background-color: white;
    padding: 30px;
    border-radius: 10px;
    width: 90%;
    max-width: 500px;
    box-shadow: 0 4px 20px rgba(0, 0, 0, 0.3);
}

.player-modal-content {
    max-width: 90%;
    height: 90vh;
    display: flex;
    flex-direction: column;
}

#game-frame {
    width: 100%;
    height: 100%;
    border: none;
    border-radius: 5px;
    margin-top: 15px;
