## Frontend - JavaScript (script.js)

```javascript name=script.js
// Game management
let games = [];

// DOM Elements
const gameGrid = document.getElementById('game-grid');
const addGameBtn = document.getElementById('add-game-btn');
const gameModal = document.getElementById('game-modal');
const playerModal = document.getElementById('player-modal');
const gameForm = document.getElementById('game-form');
const closeButtons = document.querySelectorAll('.close');

// Load games from localStorage or API
function loadGames() {
    const savedGames = localStorage.getItem('games');
    if (savedGames) {
        games = JSON.parse(savedGames);
    } else {
        // Default games for demo
        games = [
            {
                id: 1,
                title: 'Pac-Man',
                description: 'Classic arcade game',
                url: 'https://www.pacman.live/',
                image: 'https://via.placeholder.com/300x200?text=Pac-Man'
            }
        ];
    }
    displayGames();
}

// Display all games
function displayGames() {
    gameGrid.innerHTML = '';
    games.forEach(game => {
        const gameCard = document.createElement('div');
        gameCard.className = 'game-card';
        gameCard.innerHTML = `
            <img src="${game.image}" alt="${game.title}" class="game-image">
            <div class="game-info">
                <h3>${game.title}</h3>
                <p>${game.description || 'No description'}</p>
                <button class="play-btn" onclick="playGame(${game.id})">Play Now</button>
            </div>
        `;
        gameGrid.appendChild(gameCard);
    });
}

// Add new game
function addGame(gameData) {
    const newGame = {
        id: Date.now(),
        ...gameData
    };
    games.push(newGame);
    saveGames();
    displayGames();
}

// Save games to localStorage
function saveGames() {
    localStorage.setItem('games', JSON.stringify(games));
}

// Play game in modal
function playGame(gameId) {
    const game = games.find(g => g.id === gameId);
    if (game) {
        document.getElementById('player-title').textContent = game.title;
        document.getElementById('game-frame').src = game.url;
        playerModal.classList.add('active');
    }
}

// Modal controls
addGameBtn.addEventListener('click', () => {
    gameForm.reset();
    gameModal.classList.add('active');
});

closeButtons.forEach(btn => {
    btn.addEventListener('click', function() {
        this.closest('.modal').classList.remove('active');
        document.getElementById('game-frame').src = '';
    });
});

gameForm.addEventListener('submit', (e) => {
    e.preventDefault();
    const newGame = {
        title: document.getElementById('game-title').value,
        description: document.getElementById('game-description').value,
        url: document.getElementById('game-url').value,
        image: document.getElementById('game-image').value || 'https://via.placeholder.com/300x200?text=Game'
    };
    addGame(newGame);
    gameModal.classList.remove('active');
    alert('Game added successfully!');
});

// Close modal when clicking outside
window.addEventListener('click', (e) => {
    if (e.target === gameModal) gameModal.classList.remove('active');
    if (e.target === playerModal) playerModal.classList.remove('active');
});

// Initialize
loadGames();
```

## Backend - Node.js/Express (server.js)

```javascript name=server.js
const express = require('express');
const cors = require('cors');
const path = require('path');
const app = express();
const PORT = process.env.PORT || 3000;

// Middleware
app.use(cors());
app.use(express.json());
app.use(express.static('public'));

// Simple in-memory database (replace with real DB later)
let games = [
    {
        id: 1,
        title: 'Pac-Man',
        description: 'Classic arcade game',
        url: 'https://www.pacman.live/',
        image: 'https://via.placeholder.com/300x200?text=Pac-Man'
    }
];

// Routes
app.get('/api/games', (req, res) => {
    res.json(games);
});

app.post('/api/games', (req, res) => {
    const { title, description, url, image } = req.body;

    if (!title || !url) {
        return res.status(400).json({ error: 'Title and URL are required' });
    }

    const newGame = {
        id: Date.now(),
        title,
        description: description || '',
        url,
        image: image || 'https://via.placeholder.com/300x200?text=' + encodeURIComponent(title)
    };

    games.push(newGame);
    res.status(201).json(newGame);
});

app.delete('/api/games/:id', (req, res) => {
    games = games.filter(g => g.id !== parseInt(req.params.id));
    res.json({ success: true });
});

app.listen(PORT, () => {
    console.log(`🎮 Game Hub running on http://localhost:${PORT}`);
});
```

